template:
use std::fs::File;
use std::io::ErrorKind;

/// Opens "hello.txt" if it exists, or creates it if not found.
/// Panics on any other error.
pub fn open_or_create_file() -> File {
    let file_result = File::open("hello.txt");

    match file_result {
        Ok(file) => file,
        Err(error) => match error.kind() {
            [[SLOT kind_notfound]] => match [[SLOT create_call]] {
                Ok(fc) => fc,
                [[SLOT create_err]]
            },
            other_error => {
                panic!("Problem opening the file: {other_error:?}");
            }
        },
    }
}

fn main() {
    let _file = open_or_create_file();
    println!("File handle obtained successfully!");
}
